SELECT COUNT(request_id) AS request_count
FROM explanation_requests
WHERE requested_by = 1;

SELECT name 
FROM explainers 
WHERE global = 1;

SELECT name 
FROM explainers 
WHERE explainer_id = 1;

SELECT COUNT(*) 
FROM explanation_requests 
WHERE status = 'completed';

SELECT created_by, COUNT(explanation_id) AS explanations_count
FROM explanations
GROUP BY created_by;

SELECT COUNT(er.request_id) AS total_completed_explanations
FROM explanation_requests er
WHERE er.status = 'completed';

SELECT model_name
FROM models
WHERE model_id = 1;
